async () => {
  const opts = {"blockLabel":"示例 · 布局容器","tabLabel":"布局","sectionTitle":"组件 · 布局","disableBg":false,"enableBg":false};
  const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
  const matchRow = (label) =>
    [...document.querySelectorAll("[data-block-tree-row]")].find((r) => {
      const t = r.querySelector(".block-tree__label-text")?.textContent?.trim() ?? "";
      return t === label || t.startsWith(label + " ·");
    });
  const row = matchRow(opts.blockLabel);
  if (!row) return { error: "block", blockLabel: opts.blockLabel };
  row.querySelector(".block-tree__label")?.click();
  await sleep(200);
  const tab = [...document.querySelectorAll(".admin-inspector-tabs [role='tab']")].find((t) =>
    (t.textContent ?? "").includes(opts.tabLabel)
  );
  if (!tab) return { error: "tab", tabLabel: opts.tabLabel };
  tab.click();
  await sleep(280);
  if (opts.disableBg) {
    [...document.querySelectorAll("button")]
      .find((b) => b.textContent?.trim() === "关闭背景图")
      ?.click();
    await sleep(200);
  }
  if (opts.enableBg) {
    [...document.querySelectorAll("button")]
      .find((b) => b.textContent?.trim() === "启用背景图")
      ?.click();
    await sleep(300);
  }
  const h = [...document.querySelectorAll(".inspector__subtitle")].find(
    (el) => el.textContent?.trim() === opts.sectionTitle
  );
  if (!h) {
    return {
      error: "subtitle",
      sectionTitle: opts.sectionTitle,
      titles: [...document.querySelectorAll(".inspector__subtitle")].map((el) =>
        el.textContent?.trim()
      ),
    };
  }
  h.scrollIntoView({ block: "nearest" });
  await sleep(120);
  const section = h.nextElementSibling;
  if (!section?.classList.contains("inspector__section")) {
    return { error: "section", sectionTitle: opts.sectionTitle };
  }
  const pad = 6;
  const r1 = h.getBoundingClientRect();
  const r2 = section.getBoundingClientRect();
  const x = Math.min(r1.x, r2.x) - pad;
  const y = r1.y - pad;
  const right = Math.max(r1.right, r2.right) + pad;
  const bottom = r2.bottom + pad;
  return {
    x: Math.max(0, x),
    y: Math.max(0, y),
    width: right - Math.max(0, x),
    height: bottom - Math.max(0, y),
    viewportWidth: window.innerWidth,
    viewportHeight: window.innerHeight,
  };
}

